      osc.type = 'sine';
      osc.frequency.value = 800 + i * 200;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0.08, t + i * 0.2);
      g.gain.exponentialRampToValueAtTime(0.001, t + i * 0.2 + 0.1);
      osc.connect(g);
